from source import filter_expensive_items

def test_type_coercion_price():
    items = [
        {'name': 'A', 'price': 100},
        {'name': 'B', 'price': '200'},
        {'name': 'C', 'price': 300}
    ]
    threshold = 150
    expected_result = [
        {'name': 'B', 'price': '200'},
        {'name': 'C', 'price': 300}
    ]

    with pytest.raises(TypeError):
        result = filter_expensive_items(items, threshold)
